package com.example.rest_kafka_poc.controller;import com.example.rest_kafka_poc.pojo.Employee;import com.example.rest_kafka_poc.service.EmployeeServiceImpl;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.http.HttpStatus;import org.springframework.http.ResponseEntity;import org.springframework.util.ObjectUtils;import org.springframework.web.bind.annotation.*;@RestController@RequestMapping("/employee")public class EmployeeController {    @Autowired    EmployeeServiceImpl employeeServiceImpl;    @GetMapping("/")    public String getWish() {        return "Hello";    }    @PostMapping("/create")    public ResponseEntity<String> postEmployeeRecord(@RequestBody Employee employee) {        employeeServiceImpl.publishEmployee(employee);        return ResponseEntity.status(HttpStatus.OK)                .body(employee.toString());    }    @GetMapping("/get")    public ResponseEntity<String> getEmployeeRecord(@RequestParam("id") int employeeId) {        String employee = employeeServiceImpl.getEmployee(Integer.valueOf(employeeId));        return !ObjectUtils.isEmpty(employee) ?                ResponseEntity.status(HttpStatus.OK)                        .body(employee.toString()) :                ResponseEntity.status(HttpStatus.NOT_ACCEPTABLE)                        .body("No Record found");    }}